@Service
class ItemService {

    private static final Logger log = LoggerFactory.getLogger(ItemService.class);
    private final Map<Long, Item> store = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(0);

    @PostConstruct
    public void init() {
        log.info("Initializing item service with seed data");
        createItem(new CreateItemRequest("Sample Item 1", "Seed item one"));
        createItem(new CreateItemRequest("Sample Item 2", "Seed item two"));
        log.info("Item service initialized with {} items", store.size());
    }

    public List<ItemResponse> getAllItems() {
        log.info("Fetching all items from in-memory store");
        return store.values()
                .stream()
                .map(this::toResponse)
                .collect(Collectors.toList());
    }

    public ItemResponse getItemById(Long id) {
        log.info("Fetching item by id={}", id);
        Item item = store.get(id);
        if (item == null) {
            log.warn("Item not found for id={}", id);
            throw new ItemNotFoundException("Item not found with id: " + id);
        }
        log.info("Item found for id={}", id);
        return toResponse(item);
    }

    public ItemResponse createItem(CreateItemRequest request) {
        log.info("Creating new item");
        long id = idGenerator.incrementAndGet();
        Item item = new Item(id, request.name(), request.description(), Instant.now());
        store.put(id, item);
        log.info("Item created successfully with id={}", id);
        return toResponse(item);
    }

    public void deleteItem(Long id) {
        log.info("Deleting item with id={}", id);
        Item removed = store.remove(id);
        if (removed == null) {
            log.warn("Attempted to delete non-existent item with id={}", id);
            throw new ItemNotFoundException("Item not found with id: " + id);
        }
        log.info("Item deleted successfully with id={}", id);
    }

    private ItemResponse toResponse(Item item) {
        return new ItemResponse(item.id(), item.name(), item.description(), item.createdAt());
    }
}

@RestControllerAdvice
class GlobalExceptionHandler {

    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(ItemNotFoundException.class)
    public ResponseEntity<ErrorResponse> handleItemNotFound(ItemNotFoundException ex) {
        log.warn("Handled business exception: {}", ex.getMessage());
        return ResponseEntity.status(404).body(new ErrorResponse("NOT_FOUND", ex.getMessage(), Instant.now()));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleGenericException(Exception ex) {
        log.error("Unhandled exception occurred", ex);
        return ResponseEntity.status(500).body(new ErrorResponse("INTERNAL_SERVER_ERROR", "An unexpected error occurred", Instant.now()));
    }
}

